1	'use server'
2	import { prisma } from '@/lib/prisma'
3	import { requireAdmin } from '@/lib/auth'
4	import { revalidatePath } from 'next/cache'
5	import { inspectionUpdateSchema } from './schema'
6	import type { ActionResult } from '@/lib/errors'
7	
8	export async function updateInspection(
9	    id: number,
10	    input: unknown
11	): Promise<ActionResult> {
12	    try {
13	        await requireAdmin()
14	        const parsed = inspectionUpdateSchema.safeParse(input)
15	        if (!parsed.success) {
16	            return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
17	        }
18	        await prisma.inspection.update({
19	            where: { id },
20	            data: { status: parsed.data.status, comment: parsed.data.comment ?? null },
21	        })
22	        revalidatePath('/inspection')
23	        return { success: true, data: undefined }
24	    } catch (e) {
25	        console.error('updateInspection error:', e)
26	        return { success: false, error: '검수 상태 변경 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' }
27	    }
28	}
