1	'use server'
2	import { prisma } from '@/lib/prisma'
3	import { requireAdmin } from '@/lib/auth'
4	import { domainSaveSchema } from './schema'
5	import type { ActionResult } from '@/lib/errors'
6	
7	export async function createDomain(input: unknown): Promise<ActionResult<{ id: number }>> {
8	  await requireAdmin()
9	  const parsed = domainSaveSchema.safeParse(input)
10	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
11	
12	  const domain = await prisma.domain.create({ data: parsed.data })
13	  return { success: true, data: { id: domain.id } }
14	}
15	
16	export async function updateDomain(id: number, input: unknown): Promise<ActionResult> {
17	  await requireAdmin()
18	  const parsed = domainSaveSchema.safeParse(input)
19	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
20	
21	  await prisma.domain.update({ where: { id }, data: parsed.data })
22	  return { success: true, data: undefined }
23	}
24	
25	export async function deleteDomain(id: number): Promise<ActionResult> {
26	  await requireAdmin()
27	  await prisma.domain.delete({ where: { id } })
28	  return { success: true, data: undefined }
29	}
